const body = $input.first().json.body || $input.first().json;

if (!body.query) throw new Error('Missing required field: query');

const sources = body.sources || ['arxiv', 'pubmed', 'semantic_scholar'];
const timestamp = new Date().toISOString();
const sessionId = `rs-${Date.now()}`;

return [{
  json: {
    sessionId,
    query: body.query,
    sources,
    timestamp,
    status: 'INTENT_ANALYSIS'
  }
}];

const sessionData = $(' Validate & Init Session').first().json;
const gptResponse = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';

let intentData;
try {
  const cleaned = gptResponse.replace(/```json\n?|```/g, '').trim();
  intentData = JSON.parse(cleaned);
} catch(e) {
  const q = sessionData.query;
  intentData = {
    primary_keywords: [q],
    arxiv_goal: `Search arxiv.org for "${q}", extract top 8 papers as JSON: [{title, authors, abstract, url, published_date}]`,
    pubmed_goal: `Search pubmed.ncbi.nlm.nih.gov for "${q}", extract top 8 results as JSON: [{title, authors, abstract, url, pmid, published_date}]`,
    semantic_scholar_goal: `Search semanticscholar.org for "${q}", extract top 8 papers as JSON: [{title, authors, abstract, url, citation_count, year}]`,
    intent_label: 'Discovery',
    confidence: 0.7
  };
}

return [{
  json: {
    ...sessionData,
    intent_analysis: intentData,
    status: 'AGENT_DISPATCH'
  }
}];

// Evaluate Runs (aggregate across ALL incoming items)
const items = $input.all().map(i => i.json);

let runs = [];
for (const x of items) {
  if (Array.isArray(x)) {
    runs.push(...x);
  } else if (Array.isArray(x?.data)) {
    runs.push(...x.data);
  } else if (Array.isArray(x?.runs)) {
    runs.push(...x.runs);
  } else if (x && (x.run_id || x.status)) {
    runs.push(x);
  }
}

// De-dupe by run_id
const seen = new Set();
runs = runs.filter(r => {
  const id = r?.run_id ?? r?.runId ?? JSON.stringify(r);
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

const terminal = new Set(['COMPLETED','FAILED','CANCELLED']);
const allDone =
  runs.length > 0 &&
  runs.every(r => terminal.has(String(r.status || '').toUpperCase()));

return [{
  json: {
    raw: items,
    runs,
    allDone
  }
}];

// Rehydrate per-run items so each run_id is polled individually
const inItem = $input.first().json;

const arr = Array.isArray(inItem.runs)
  ? inItem.runs
  : (Array.isArray(inItem.raw) ? inItem.raw : []);

const runIds = arr
  .map(r => r?.run_id || r?.runId)
  .filter(Boolean);

const ctx = {
  sessionId: inItem.sessionId,
  query: inItem.query,
  intent_analysis: inItem.intent_analysis
};

return runIds.map(runId => ({
  json: {
    ...ctx,
    runId,
    run_id: runId
  }
}));

// On completion, aggregate run results and map back to sources
// Pull session context from Parse Intent
const sessionData = $(' Parse Intent').first().json;

const inItems = $input.all().map(i => i.json);

let runsRaw = [];
for (const x of inItems) {
  if (Array.isArray(x)) {
    runsRaw.push(...x);
  } else if (Array.isArray(x?.data)) {
    runsRaw.push(...x.data);
  } else if (Array.isArray(x?.runs)) {
    runsRaw.push(...x.runs);
  } else if (x?.run_id || x?.status) {
    runsRaw.push(x);
  }
}

const runs = runsRaw.map(run => ({
  run_id: run.run_id ?? null,
  status: String(run.status ?? '').toUpperCase(),
  goal: run.goal ?? '',
  result: run.result ?? null,
  error: run.error ?? null
}));

// Tag each run with which source it belongs to based on goal text
const sourceMap = [
  { key: 'arxiv', match: 'arxiv' },
  { key: 'pubmed', match: 'pubmed' },
  { key: 'semantic_scholar', match: 'semantic' }
];

const taggedRuns = runs.map(run => {
  const goalLower = (run.goal || '').toLowerCase();
  const resultText = typeof run.result === 'string' ? run.result : JSON.stringify(run.result || '');
  let source = 'unknown';
  for (const s of sourceMap) {
    if (goalLower.includes(s.match) || resultText.toLowerCase().includes(s.match)) {
      source = s.key;
      break;
    }
  }
  return { ...run, source };
});

return [{
  json: {
    sessionId: sessionData.sessionId,
    query: sessionData.query,
    intent_analysis: sessionData.intent_analysis,
    timestamp: sessionData.timestamp,
    taggedRuns,
    status: 'NORMALIZING'
  }
}];

// Normalize ArXiv TinyFish result from completed run
const root = $input.first().json;
const taggedRuns = root.taggedRuns || [];

// Find the arxiv run
const run = taggedRuns.find(r => r.source === 'arxiv') || {};

let papers = [];
try {
  const raw = run.result;
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  const rawPapers = Array.isArray(parsed) ? parsed : (parsed?.papers || parsed?.results || parsed?.items || []);

  papers = rawPapers.slice(0, 10).map(p => ({
    title: p.title || 'Untitled',
    authors: Array.isArray(p.authors) ? p.authors.slice(0, 3).join(', ') : (p.authors || ''),
    abstract: (p.abstract || p.summary || '').substring(0, 400),
    url: p.url || p.link || '',
    published: p.published_date || p.date || p.year || '',
    source: 'arxiv',
    citationCount: null,
    doi: p.arxiv_id ? `arxiv:${p.arxiv_id}` : ''
  }));
} catch(e) {
  papers = [];
}

return [{ json: { source: 'arxiv', papers, count: papers.length, sessionId: root.sessionId, status: run.status || 'COMPLETED' } }];

// Normalize PubMed TinyFish result from completed run
const root = $input.first().json;
const taggedRuns = root.taggedRuns || [];

const run = taggedRuns.find(r => r.source === 'pubmed') || {};

let papers = [];
try {
  const raw = run.result;
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  const rawPapers = Array.isArray(parsed) ? parsed : (parsed?.papers || parsed?.results || parsed?.items || []);

  papers = rawPapers.slice(0, 10).map(p => ({
    title: p.title || 'Untitled',
    authors: Array.isArray(p.authors) ? p.authors.slice(0, 3).join(', ') : (p.authors || ''),
    abstract: (p.abstract || '').substring(0, 400),
    url: p.url || (p.pmid ? `https://pubmed.ncbi.nlm.nih.gov/${p.pmid}/` : ''),
    published: p.published_date || p.date || p.year || '',
    source: 'pubmed',
    citationCount: null,
    doi: p.pmid ? `pmid:${p.pmid}` : ''
  }));
} catch(e) {
  papers = [];
}

return [{ json: { source: 'pubmed', papers, count: papers.length, sessionId: root.sessionId, status: run.status || 'COMPLETED' } }];

// Normalize Semantic Scholar TinyFish result from completed run
const root = $input.first().json;
const taggedRuns = root.taggedRuns || [];

const run = taggedRuns.find(r => r.source === 'semantic_scholar') || {};

let papers = [];
try {
  const raw = run.result;
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  const rawPapers = Array.isArray(parsed) ? parsed : (parsed?.papers || parsed?.results || parsed?.items || []);

  papers = rawPapers.slice(0, 10).map(p => ({
    title: p.title || 'Untitled',
    authors: Array.isArray(p.authors) ? p.authors.slice(0, 3).join(', ') : (p.authors || ''),
    abstract: (p.abstract || '').substring(0, 400),
    url: p.url || '',
    published: p.year ? String(p.year) : (p.published_date || ''),
    source: 'semantic_scholar',
    citationCount: typeof p.citation_count === 'number' ? p.citation_count : (p.citationCount || null),
    doi: ''
  }));
} catch(e) {
  papers = [];
}

return [{ json: { source: 'semantic_scholar', papers, count: papers.length, sessionId: root.sessionId, status: run.status || 'COMPLETED' } }];

// Aggregate and deduplicate all TinyFish scout results
const allInputs = $input.all();
const sessionData = $(' Parse Intent').first().json;

let allPapers = [];
const sourceCounts = {};
const scoutStatuses = {};

for (const input of allInputs) {
  const { source, papers, count, status } = input.json;
  sourceCounts[source] = count;
  scoutStatuses[source] = status;
  allPapers = allPapers.concat(papers);
}

// Deduplicate by title
const seen = new Set();
const dedupedPapers = allPapers.filter(p => {
  const key = p.title.toLowerCase().substring(0, 60);
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Sort by citation count desc, then recency
dedupedPapers.sort((a, b) => {
  if (b.citationCount !== null && a.citationCount !== null) {
    return (b.citationCount || 0) - (a.citationCount || 0);
  }
  return (b.published || '').localeCompare(a.published || '');
});

return [{
  json: {
    sessionId: sessionData.sessionId,
    query: sessionData.query,
    intent_analysis: sessionData.intent_analysis,
    timestamp: sessionData.timestamp,
    sources_searched: Object.keys(sourceCounts),
    source_counts: sourceCounts,
    scout_statuses: scoutStatuses,
    total_raw: allPapers.length,
    total_deduplicated: dedupedPapers.length,
    papers: dedupedPapers,
    status: 'SYNTHESIS'
  }
}];

